# ── PDF support ───────────────────────────────────────────────────────────────
def extract_pdf_text(pdf_bytes: bytes) -> str:
    """Extract text from a PDF file using pypdf."""
    try:
        from pypdf import PdfReader
        reader = PdfReader(io.BytesIO(pdf_bytes))
        pages = [page.extract_text() or "" for page in reader.pages]
        return "\n\n".join(pages).strip()
    except ImportError:
        return "[PDF support requires pypdf — add it to requirements.txt]"
    except Exception as e:
        return f"[PDF read error: {e}]"

# ── OAuth helpers ─────────────────────────────────────────────────────────────
def _secret(key: str, default: str = "") -> str:
    """Safely read from st.secrets or return default."""
    try:
        return st.secrets.get(key, default)
    except Exception:
        return default

def google_oauth_url() -> str | None:
    """Build Google OAuth 2.0 authorisation URL."""
    client_id = _secret("GOOGLE_CLIENT_ID")
    redirect  = _secret("OAUTH_REDIRECT_URI")
    if not client_id or not redirect:
        return None
    params = {
        "client_id":     client_id,
        "redirect_uri":  redirect,
        "response_type": "code",
        "scope":         "openid email profile",
        "state":         "google",
        "access_type":   "online",
        "prompt":        "select_account",
    }
    return "https://accounts.google.com/o/oauth2/v2/auth?" + urllib.parse.urlencode(params)

def microsoft_oauth_url() -> str | None:
    """Build Microsoft OAuth 2.0 authorisation URL."""
    client_id = _secret("MICROSOFT_CLIENT_ID")
    redirect  = _secret("OAUTH_REDIRECT_URI")
    tenant    = _secret("MICROSOFT_TENANT_ID", "common")
    if not client_id or not redirect:
        return None
    params = {
        "client_id":     client_id,
        "redirect_uri":  redirect,
        "response_type": "code",
        "scope":         "openid email profile",
        "state":         "microsoft",
    }
    return f"https://login.microsoftonline.com/{tenant}/oauth2/v2.0/authorize?" + urllib.parse.urlencode(params)

def handle_oauth_callback() -> bool:
    """
    Called once at startup. Detects an OAuth callback via query params,
    exchanges the code for user info, and logs the user in.
    Returns True if a callback was handled.
    """
    params = st.query_params
    code  = params.get("code", "")
    state = params.get("state", "")
    if not code or state not in ("google", "microsoft"):
        return False

    redirect = _secret("OAUTH_REDIRECT_URI")

    try:
        if state == "google":
            # Exchange code
            token_resp = requests.post("https://oauth2.googleapis.com/token", data={
                "code":          code,
                "client_id":     _secret("GOOGLE_CLIENT_ID"),
                "client_secret": _secret("GOOGLE_CLIENT_SECRET"),
                "redirect_uri":  redirect,
                "grant_type":    "authorization_code",
            }, timeout=10).json()
            access_token = token_resp.get("access_token", "")
            user_info = requests.get(
                "https://www.googleapis.com/oauth2/v2/userinfo",
                headers={"Authorization": f"Bearer {access_token}"}, timeout=10,
            ).json()
            email    = user_info.get("email", "")
            name     = user_info.get("name", email.split("@")[0])

        else:  # microsoft
            tenant = _secret("MICROSOFT_TENANT_ID", "common")
            token_resp = requests.post(
                f"https://login.microsoftonline.com/{tenant}/oauth2/v2.0/token",
                data={
                    "code":          code,
                    "client_id":     _secret("MICROSOFT_CLIENT_ID"),
                    "client_secret": _secret("MICROSOFT_CLIENT_SECRET"),
                    "redirect_uri":  redirect,
                    "grant_type":    "authorization_code",
                }, timeout=10,
            ).json()
            access_token = token_resp.get("access_token", "")
            user_info = requests.get(
                "https://graph.microsoft.com/v1.0/me",
                headers={"Authorization": f"Bearer {access_token}"}, timeout=10,
            ).json()
            email = user_info.get("mail") or user_info.get("userPrincipalName", "")
            name  = user_info.get("displayName", email.split("@")[0])

        if not email:
            st.error("OAuth login failed — could not retrieve email.")
            return True

        # Find or create user
        existing = next((u for u in st.session_state.users if u["email"] == email), None)
        if not existing:
            existing = {
                "id":       f"u{int(time.time()*1000)}",
                "email":    email,
                "username": name,
                "pw_hash":  "",
                "rec":      "",
            }
            st.session_state.users.append(existing)

        st.session_state.session = {
            "id":       existing["id"],
            "email":    email,
            "username": existing["username"],
            "is_admin": False,
        }
        # Clear OAuth params and redirect to dashboard/onboard
        st.query_params.clear()
        target = "dashboard" if st.session_state.profile else "onboard"
        go(target)
        return True

    except Exception as e:
        st.error(f"OAuth error: {e}")
        return True

