def init_state():
    _admin = {
        "id":ADMIN_ID,"email":ADMIN_EMAIL,"username":ADMIN_USERNAME,
        "pw_hash":"","rec":"","is_admin":True,
    }
    defaults = {
        "screen":       "apikey",
        "groq_key":     "",
        "users":        [_admin],
        "session":      None,
        "profile":      None,
        "spaces":       [],
        "notes":        {},
        "cur_space":    None,
        "ob_step":      0,
        "ob_grade":     "",
        "ob_region":    "",
        "ob_curr":      "",
        "ob_picked":    [],
        "ob_profs":     {},
        "tip_idx":      random.randint(0, len(STUDY_TIPS)-1),
        "plan_text":    "",
        "show_settings":False,
    }
    for k, v in defaults.items():
        if k not in st.session_state:
            st.session_state[k] = v

# ── Helpers ───────────────────────────────────────────────────────────────────
def go(screen: str):
    st.session_state.screen = screen
    st.rerun()

def get_groq():
    return Groq(api_key=st.session_state.groq_key)

def subStr(profile: dict) -> str:
    return ", ".join(
        f"{s['name']} ({s['proficiency']})" for s in (profile.get("subjects") or [])
    ) or "General"

