def screen_space():
    render_sidebar()
    space   = st.session_state.cur_space
    profile = st.session_state.profile

    # Header
    h1, h2 = st.columns([1, 10])
    with h1:
        if st.button("←"): go("dashboard")
    with h2:
        st.markdown(
            f'<div style="display:flex;align-items:center;gap:9px;padding-top:4px">'            f'<div style="width:26px;height:26px;border-radius:6px;background:{space["color"]}22;'            f'display:flex;align-items:center;justify-content:center;font-size:14px;color:{space["color"]}">{space["icon"]}</div>'            f'<span style="font-weight:900;font-size:15px">{space["name"]}</span>'            f'<span style="font-size:11px;color:#404040;margin-left:4px">{space["subject"]}</span></div>',
            unsafe_allow_html=True,
        )
    st.markdown('<hr class="elixir-divider"/>', unsafe_allow_html=True)

    # Uploader
    uk = st.session_state.get(f'uk_{space["id"]}', 0)
    st.markdown(
        '<p style="font-weight:800;font-size:14px;margin-bottom:2px;color:#E2E2F0">Upload revision material</p>'        '<p style="font-size:12px;color:#404060;margin-bottom:8px">'        'Images, PDFs, .txt, .md, .csv and more — notes generated automatically</p>',
        unsafe_allow_html=True,
    )
    uploaded = st.file_uploader(
        "Upload",
        type=["png","jpg","jpeg","gif","webp","bmp",
              "pdf",
              "txt","md","csv","json","py","js","ts","java",
              "cpp","c","xml","yaml","yml","tex","log"],
        key=f'uploader_{space["id"]}_{uk}',
        label_visibility="collapsed",
    )

    if uploaded:
        is_image = uploaded.type.startswith("image/")
        is_pdf   = uploaded.type == "application/pdf" or uploaded.name.lower().endswith(".pdf")
        file_icon = "🖼" if is_image else ("📕" if is_pdf else "📄")

        st.markdown(
            f'<div class="tip-box">{file_icon} <strong>{uploaded.name}</strong> — analysing now…</div>',
            unsafe_allow_html=True,
        )
        prog = st.progress(0, text="Reading file…")
        prog.progress(15, text="Preparing content…")

        with st.spinner(f"⚗ Elixir AI is studying {uploaded.name}…"):
            try:
                raw = uploaded.read()
                prog.progress(35, text="Sending to Groq AI…")

                if is_image:
                    analysis = ai_analyze_image(raw, profile)
                elif is_pdf:
                    text = extract_pdf_text(raw)
                    analysis = ai_analyze_text(text, profile)
                else:
                    analysis = ai_analyze_text(raw.decode("utf-8","ignore"), profile)

                prog.progress(88, text="Saving study notes…")
                note = {
                    "id":       f"n{int(time.time()*1000)}",
                    "title":    uploaded.name.rsplit(".",1)[0],
                    "is_image": is_image,
                    "b64_thumb":base64.b64encode(raw).decode() if is_image else None,
                    "analysis": analysis,
                    "filename": uploaded.name,
                    "created":  __import__("datetime").datetime.now().strftime("%d %b %Y, %H:%M"),
                }
                if space["id"] not in st.session_state.notes:
                    st.session_state.notes[space["id"]] = []
                st.session_state.notes[space["id"]].insert(0, note)
                st.session_state[f'uk_{space["id"]}'] = uk + 1
                prog.progress(100, text="Done ✓")
                st.success("Study notes saved!")
                st.rerun()
            except Exception as e:
                prog.empty()
                st.error(f"Analysis failed: {e}")

    # Notes list
    notes = st.session_state.notes.get(space["id"], [])
    if notes:
        st.markdown(
            f'<h4 style="font-weight:900;font-size:15px;margin-top:28px;margin-bottom:14px;'            f'color:#E2E2F0;border-left:3px solid #3BBFAF;padding-left:10px">'            f'Study Notes ({len(notes)})</h4>',
            unsafe_allow_html=True,
        )
        for i, note in enumerate(notes):
            label = f"{'🖼' if note['is_image'] else '📄'}  {note['title']}  ·  {note['created']}"
            with st.expander(label, expanded=(i==0)):
                if note["is_image"] and note.get("b64_thumb"):
                    st.image(base64.b64decode(note["b64_thumb"]), use_container_width=True, caption=note["filename"])
                st.markdown(note["analysis"])
                c1, c2 = st.columns(2)
                with c1:
                    if st.button("Copy notes", key=f"copy_{note['id']}"):
                        st.code(note["analysis"], language=None)
                with c2:
                    st.download_button(
                        "Download .txt", note["analysis"],
                        file_name=f"{note['title']}_notes.txt", mime="text/plain",
                        key=f"dl_{note['id']}",
                    )
    else:
        st.markdown(
            '<div style="text-align:center;padding:40px 20px;border:2px dashed #1A1A2E;border-radius:14px;margin-top:16px">'            '<div style="font-size:28px;margin-bottom:10px;opacity:.3">↑</div>'            '<p style="color:#404060;font-size:14px">Upload your first file to generate study notes.</p></div>',
            unsafe_allow_html=True,
        )


def screen_studyplan():
    render_sidebar()
    col = st.columns([1,2,1])[1]
    with col:
        if st.button("← Dashboard"): go("dashboard")
        st.markdown('<h2 style="font-weight:900;margin-bottom:20px">Weekly Study Plan</h2>', unsafe_allow_html=True)

        if not st.session_state.plan_text:
            with st.spinner("⚗ Building your personalised study plan…"):
                try:
                    st.session_state.plan_text = ai_study_plan(st.session_state.spaces)
                except Exception as e:
                    st.error(f"Could not generate plan: {e}"); return

        st.markdown(
            f'<div class="analysis-box">{st.session_state.plan_text.replace(chr(10),"<br/>")}</div>',
            unsafe_allow_html=True,
        )
        c1, c2 = st.columns(2)
        with c1:
            if st.button("Regenerate", use_container_width=True):
                st.session_state.plan_text = ""; st.rerun()
        with c2:
            st.download_button("Download plan", st.session_state.plan_text,
                               file_name="study_plan.txt", mime="text/plain",
                               use_container_width=True)

# ── Router ────────────────────────────────────────────────────────────────────
def main():
    init_state()
    inject_css()

    # Handle OAuth callback before rendering anything
    if handle_oauth_callback():
        return

    screen = st.session_state.screen
    if   screen == "apikey":    screen_apikey()
    elif screen == "welcome":   screen_welcome()
    elif screen == "signup":    screen_signup()
    elif screen == "signin":    screen_signin()
    elif screen == "onboard":   screen_onboard()
    elif screen == "dashboard": screen_dashboard()
    elif screen == "new_space": screen_new_space()
    elif screen == "space":     screen_space()
    elif screen == "studyplan": screen_studyplan()
    else:
        st.error(f"Unknown screen: {screen}")
        go("welcome")

if __name__ == "__main__":
    main()
